module top(clk);
input wire clk;

reg [7:0] counter = 0;
always @(posedge clk) begin
    counter = counter + 1;
end

reg [7:0] save;
always @(posedge clk) begin
    save = counter;
    $display("counter %x save %x", counter, save);
end
endmodule
